# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

import os
import json
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
import functions_framework
from datetime import datetime

# Initialize clients
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

# Configuration
PROJECT_ID = os.environ.get('GCP_PROJECT')
PUBSUB_TOPIC = os.environ.get('PUBSUB_TOPIC', f'projects/{PROJECT_ID}/topics/file-processed')
FIRESTORE_COLLECTION = os.environ.get('FIRESTORE_COLLECTION', 'processed_files')

@functions_framework.cloud_event
def process_file(cloud_event):
    """
    Triggered by Cloud Storage event when a file is uploaded.
    Processes the file, writes metadata to Firestore, and publishes to Pub/Sub.
    """
    data = cloud_event.data
    
    bucket_name = data['bucket']
    file_name = data['name']
    
    print(f'Processing file: {file_name} from bucket: {bucket_name}')
    
    try:
        # Read file from Cloud Storage
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        # Get file content and metadata
        file_content = blob.download_as_text()
        file_size = blob.size
        content_type = blob.content_type
        created_time = blob.time_created
        
        # Process file content (example: count lines if text file)
        line_count = len(file_content.split('\n')) if content_type and 'text' in content_type else 0
        
        # Create document ID from filename
        doc_id = file_name.replace('/', '_').replace('.', '_')
        
        # Write to Firestore
        doc_ref = firestore_client.collection(FIRESTORE_COLLECTION).document(doc_id)
        doc_data = {
            'file_name': file_name,
            'bucket': bucket_name,
            'size_bytes': file_size,
            'content_type': content_type,
            'line_count': line_count,
            'created_time': created_time,
            'processed_time': datetime.utcnow(),
            'status': 'processed',
            'gcs_uri': f'gs://{bucket_name}/{file_name}'
        }
        doc_ref.set(doc_data)
        print(f'Written to Firestore: {doc_id}')
        
        # Publish message to Pub/Sub
        message_data = {
            'file_name': file_name,
            'bucket': bucket_name,
            'size': file_size,
            'firestore_doc_id': doc_id,
            'event_type': 'file_processed',
            'timestamp': datetime.utcnow().isoformat()
        }
        
        message_bytes = json.dumps(message_data).encode('utf-8')
        future = publisher.publish(PUBSUB_TOPIC, message_bytes)
        message_id = future.result()
        print(f'Published to Pub/Sub: {message_id}')
        
        # Update Firestore with Pub/Sub message ID
        doc_ref.update({
            'pubsub_message_id': message_id
        })
        
        return {'status': 'success', 'file': file_name}
        
    except Exception as e:
        print(f'Error processing file {file_name}: {str(e)}')
        
        # Log error to Firestore
        try:
            error_doc_ref = firestore_client.collection('processing_errors').document()
            error_doc_ref.set({
                'file_name': file_name,
                'bucket': bucket_name,
                'error': str(e),
                'timestamp': datetime.utcnow()
            })
        except:
            pass
        
        raise


@functions_framework.http
def http_trigger(request):
    """
    HTTP endpoint to manually trigger file processing or query Firestore.
    """
    request_json = request.get_json(silent=True)
    action = request_json.get('action', 'list') if request_json else 'list'
    
    try:
        if action == 'process':
            # Manual file processing
            bucket_name = request_json.get('bucket')
            file_name = request_json.get('file')
            
            if not bucket_name or not file_name:
                return {'error': 'bucket and file parameters required'}, 400
            
            bucket = storage_client.bucket(bucket_name)
            blob = bucket.blob(file_name)
            
            if not blob.exists():
                return {'error': 'File not found'}, 404
            
            # Process file
            file_content = blob.download_as_text()
            file_size = blob.size
            
            doc_id = file_name.replace('/', '_').replace('.', '_')
            doc_ref = firestore_client.collection(FIRESTORE_COLLECTION).document(doc_id)
            doc_ref.set({
                'file_name': file_name,
                'bucket': bucket_name,
                'size_bytes': file_size,
                'processed_time': datetime.utcnow(),
                'status': 'manually_processed'
            })
            
            return {'status': 'success', 'doc_id': doc_id}
            
        elif action == 'list':
            # List processed files from Firestore
            limit = request_json.get('limit', 10) if request_json else 10
            docs = firestore_client.collection(FIRESTORE_COLLECTION).limit(limit).stream()
            
            results = []
            for doc in docs:
                doc_dict = doc.to_dict()
                doc_dict['id'] = doc.id
                if 'processed_time' in doc_dict:
                    doc_dict['processed_time'] = doc_dict['processed_time'].isoformat()
                if 'created_time' in doc_dict and doc_dict['created_time']:
                    doc_dict['created_time'] = doc_dict['created_time'].isoformat()
                results.append(doc_dict)
            
            return {'files': results, 'count': len(results)}
            
        elif action == 'get':
            # Get specific file details
            doc_id = request_json.get('doc_id')
            if not doc_id:
                return {'error': 'doc_id parameter required'}, 400
            
            doc = firestore_client.collection(FIRESTORE_COLLECTION).document(doc_id).get()
            if not doc.exists:
                return {'error': 'Document not found'}, 404
            
            doc_dict = doc.to_dict()
            doc_dict['id'] = doc.id
            if 'processed_time' in doc_dict:
                doc_dict['processed_time'] = doc_dict['processed_time'].isoformat()
            
            return doc_dict
            
        else:
            return {'error': 'Invalid action'}, 400
            
    except Exception as e:
        print(f'Error: {str(e)}')
        return {'error': str(e)}, 500